const SVG_NS = "http://www.w3.org/2000/svg";

/* A stroke-based UI icon as an <svg class="i"> element. */
function svgIcon(name, cls = "") {
  const inner = UI_ICONS[name] || UI_ICONS["package"];
  const s = document.createElementNS(SVG_NS, "svg");
  s.setAttribute("viewBox", "0 0 24 24");
  s.setAttribute("fill", "none");
  s.setAttribute("stroke", "currentColor");
  s.setAttribute("stroke-width", "2");
  s.setAttribute("stroke-linecap", "round");
  s.setAttribute("stroke-linejoin", "round");
  s.setAttribute("aria-hidden", "true");
  s.setAttribute("class", "i" + (cls ? " " + cls : ""));
  s.innerHTML = inner;
  return s;
}

/* A brand mark (filled glyph) as an <svg class="i brand-glyph"> element. */
function brandSvg(slug, cls = "") {
  const b = BRAND_ICONS[slug];
  if (!b) return null;
  const s = document.createElementNS(SVG_NS, "svg");
  s.setAttribute("viewBox", "0 0 24 24");
  s.setAttribute("fill", "currentColor");
  s.setAttribute("aria-hidden", "true");
  s.setAttribute("class", "i brand-glyph" + (cls ? " " + cls : ""));
  const p = document.createElementNS(SVG_NS, "path");
  p.setAttribute("d", b[1]);
  s.append(p);
  return s;
}

/* Accepts an icon name OR an emoji (from the API) and returns an icon name. */
function iconName(spec, fallback = "package") {
  if (!spec) return fallback;
  if (UI_ICONS[spec]) return spec;
  if (EMOJI_ICONS[spec]) return EMOJI_ICONS[spec];
  const bare = String(spec).replace(/️/g, "");
  return EMOJI_ICONS[bare] || fallback;
}

/* Inline icon element from a name or emoji — the everyday helper. */
function ic(spec, cls = "") {
  return svgIcon(iconName(spec), cls);
}

/* Find a brand mark for free-form text (service label, image ref, app id).
   Tries exact normalized match first, then word-level, then substring for
   longer keys so "nextcloud-app" or "ghcr.io/xyz/grafana:10" still match. */
function brandSlug(...texts) {
  for (const t of texts) {
    if (!t) continue;
    let s = String(t).toLowerCase();
    const imgBase = s.includes("/") || s.includes(":")
      ? (s.split("/").pop() || "").split(":")[0] : "";
    for (const cand of [s, imgBase]) {
      if (!cand) continue;
      const norm = cand.replace(/[^a-z0-9]/g, "");
      if (BRAND_ALIASES[norm]) return BRAND_ALIASES[norm];
    }
    for (const part of s.split(/[^a-z0-9]+/)) {
      if (part.length >= 3 && BRAND_ALIASES[part]) return BRAND_ALIASES[part];
    }
    const norm = s.replace(/[^a-z0-9]/g, "");
    for (const [alias, slug] of Object.entries(BRAND_ALIASES)) {
      if (alias.length >= 4 && norm.includes(alias)) return slug;
    }
  }
  return null;
}

function brandColor(slug) {
  const b = BRAND_ICONS[slug];
  return b ? "#" + b[0] : null;
}

/* Some brand colors are too dark/bright for a solid tile — pick a readable
   pair (tile background gradient + glyph color) per theme via CSS variables;
   here we only decide if the raw brand color is usable as a background. */
function brandTileStyle(slug) {
  const hex = BRAND_ICONS[slug] ? BRAND_ICONS[slug][0] : "888888";
  const r = parseInt(hex.slice(0, 2), 16), g = parseInt(hex.slice(2, 4), 16),
        b = parseInt(hex.slice(4, 6), 16);
  const lum = (0.2126 * r + 0.7152 * g + 0.0722 * b) / 255;
  // very dark marks get a lifted background so the tile reads on dark themes;
  // very light ones get a dimmed one so the white glyph keeps contrast
  if (lum < 0.16) return `background:linear-gradient(135deg,#${hex} 0%,color-mix(in srgb,#${hex} 55%,#6b7684) 130%)`;
  if (lum > 0.82) return `background:linear-gradient(135deg,color-mix(in srgb,#${hex} 80%,#3b4552),color-mix(in srgb,#${hex} 55%,#232b36))`;
  return `background:linear-gradient(135deg,color-mix(in srgb,#${hex} 88%,#fff),#${hex})`;
}

/* Replace <span data-icon="name"> placeholders (static HTML) with SVGs. */
function hydrateIcons(root = document) {
  root.querySelectorAll("[data-icon]").forEach((n) => {
    const s = svgIcon(iconName(n.dataset.icon, "circle"), n.dataset.iconClass || "");
    n.replaceChildren(s);
  });
}
